  values
  (v_s2, 'on_sale', '현대', '캐스퍼', '경차', 2022, 13500000, 18000, '흰색', '가솔린', '자동', 998, 4, '서울', true, array['후방카메라','스마트키','크루즈컨트롤','열선시트'], '2022년식 캐스퍼로 주행거리 1만8천km의 무사고 차량입니다. 도심 출퇴근용으로만 운행했고 외관과 실내 상태 모두 깨끗합니다. 경차라 유지비 부담이 적고 주차도 편합니다.'),
  (v_s2, 'on_sale', '기아', '모닝', '경차', 2019, 7900000, 62000, '은색', '가솔린', '자동', 998, 5, '경기', true, array['후방카메라','블루투스','스마트키'], '2019년식 모닝, 주행 6만2천km의 무사고 차량입니다. 첫차나 세컨카로 부담 없이 타기 좋고 연비도 우수합니다. 정기점검을 꾸준히 받아 엔진 상태가 좋습니다.'),
  (v_s2, 'on_sale', '기아', '레이', '경차', 2021, 11800000, 34000, '흰색', '가솔린', '자동', 998, 5, '인천', true, array['후방카메라','열선시트','스마트키','통풍시트'], '2021년식 레이로 박스형 디자인 덕분에 실내공간이 매우 넓습니다. 주행 3만4천km 무사고이며 짐을 많이 싣는 분께 추천합니다. 슬라이딩 도어로 좁은 곳에서도 승하차가 편합니다.'),
  (v_s2, 'on_sale', '쉐보레', '스파크', '경차', 2018, 5800000, 78000, '빨강', '가솔린', '자동', 999, 5, '대구', true, array['후방카메라','블루투스','에어백'], '2018년식 스파크로 주행 7만8천km입니다. 가벼운 차체로 도심 주행이 민첩하고 유지비가 매우 저렴합니다. 소소한 생활기스는 있으나 무사고 차량입니다.'),
  (v_s2, 'on_sale', '쉐보레', '올란도', '기타', 2016, 4900000, 138000, '은색', '디젤', '자동', 1998, 7, '충북', false, array['후방카메라','블루투스','에어백'], '2016년식 올란도 디젤 7인승으로 주행 13만8천km입니다. 과거 앞범퍼 교체 이력이 있으나 운행에 지장 없습니다. 7인승 다목적 차량을 저렴하게 찾는 분께 적합합니다.'),
  (v_s2, 'on_sale', '현대', '아반떼 하이브리드', '준중형차', 2023, 24500000, 21000, '회색', '하이브리드', '자동', 1580, 5, '경기', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션','어댑티브크루즈'], '2023년식 아반떼 하이브리드로 주행 2만1천km의 무사고 차량입니다. 복합연비가 매우 뛰어나 장거리 주행 시 연료비 절감 효과가 큽니다. 최신 안전옵션이 풍부하게 들어가 있습니다.'),
  (v_s2, 'on_sale', '벤츠', 'GLE450', 'SUV', 2022, 78000000, 31000, '검정', '가솔린', '자동', 2999, 5, '서울', true, array['통풍시트','파노라마선루프','어댑티브크루즈','헤드업디스플레이','내비게이션','후방카메라'], '2022년식 벤츠 GLE450으로 주행 3만1천km의 무사고 대형 SUV입니다. 강력한 직렬 6기통 엔진과 럭셔리한 실내로 프리미엄 SUV의 정점을 보여줍니다. 서울 지역 비흡연 차량으로 풀옵션에 가깝습니다.'),
  (v_s2, 'on_sale', '현대', '쏘나타', '중형차', 2019, 16500000, 88000, '검정', 'LPG', '자동', 1999, 5, '광주', false, array['후방카메라','스마트키','내비게이션','열선시트'], '2019년식 쏘나타 LPG 모델로 주행 8만8천km입니다. 과거 후방 경미 접촉 사고 이력이 있으나 수리 후 정상 운행 중입니다. LPG라 연료비가 저렴해 운행이 많은 분께 적합합니다.'),
  (v_s2, 'on_sale', '현대', '그랜저 GN7 하이브리드', '대형차', 2023, 38500000, 19000, '검정', '하이브리드', '자동', 1598, 5, '서울', true, array['통풍시트','파노라마선루프','어댑티브크루즈','내비게이션','헤드업디스플레이','후방카메라'], '2023년식 그랜저 GN7 하이브리드로 주행 1만9천km의 무사고 차량입니다. 신형 디자인과 정숙한 하이브리드 시스템으로 고급스러운 승차감을 제공합니다. 풀옵션에 가까운 사양으로 만족도가 높습니다.'),
  (v_s2, 'on_sale', '기아', 'K8', '대형차', 2022, 31000000, 37000, '회색', '가솔린', '자동', 2497, 5, '경기', true, array['통풍시트','파노라마선루프','내비게이션','헤드업디스플레이','후방카메라'], '2022년식 K8로 주행 3만7천km의 무사고 대형 세단입니다. 넓은 실내와 부드러운 승차감으로 장거리 운전이 편안합니다. 고급 옵션이 다수 포함되어 있습니다.'),
  (v_s2, 'on_sale', '현대', '투싼', 'SUV', 2022, 27500000, 28000, '흰색', '가솔린', '자동', 1598, 5, '서울', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션','어댑티브크루즈'], '2022년식 투싼으로 주행 2만8천km의 무사고 차량입니다. 도심형 SUV로 시원시원한 디자인과 넉넉한 적재공간을 갖췄습니다. 서울에서 출퇴근 위주로 운행해 상태가 우수합니다.'),
  (v_s2, 'on_sale', '기아', '셀토스', 'SUV', 2021, 22000000, 33000, '파랑', '가솔린', '자동', 1598, 5, '경기', true, array['후방카메라','열선시트','스마트키','내비게이션'], '2021년식 셀토스로 주행 3만3천km의 무사고 소형 SUV입니다. 경기 지역에서 깔끔하게 관리된 차량으로 첫 SUV로 부담 없이 타기 좋습니다. 도심과 근교 나들이에 적합합니다.'),
  (v_s2, 'on_sale', '현대', '코나', 'SUV', 2022, 23500000, 26000, '빨강', '하이브리드', '자동', 1580, 5, '서울', true, array['후방카메라','통풍시트','내비게이션','어댑티브크루즈'], '2022년식 코나 하이브리드로 주행 2만6천km의 무사고 차량입니다. 연비가 뛰어난 하이브리드 SUV로 서울 도심 운행에 최적입니다. 개성 있는 디자인과 실용성을 모두 갖췄습니다.'),
  (v_s2, 'on_sale', '기아', '스포티지 하이브리드', 'SUV', 2023, 29800000, 22000, '회색', '하이브리드', '자동', 1598, 5, '경기', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션','어댑티브크루즈'], '2023년식 스포티지 하이브리드로 주행 2만2천km의 무사고 차량입니다. 넓은 실내와 우수한 연비로 패밀리 SUV로 인기가 높습니다. 경기 지역 비흡연 차량으로 실내가 깨끗합니다.'),
