  (v_s2, 'on_sale', '쉐보레', '트레일블레이저', 'SUV', 2021, 19500000, 48000, '검정', '가솔린', '자동', 1341, 5, '대전', false, array['후방카메라','열선시트','내비게이션'], '2021년식 트레일블레이저로 주행 4만8천km입니다. 과거 측면 문짝 교환 이력이 있으나 골격 손상 없는 외판 수리입니다. 가성비 좋은 도심형 SUV를 찾는 분께 추천합니다.'),
  (v_s2, 'on_sale', '현대', '싼타페', 'SUV', 2020, 26500000, 67000, '흰색', '디젤', '자동', 2199, 7, '강원', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션','어댑티브크루즈'], '2020년식 싼타페 디젤 7인승으로 주행 6만7천km의 무사고 차량입니다. 강원 지역에서 운행했으며 패밀리카로 넉넉한 공간을 자랑합니다. 디젤 특유의 강한 토크로 장거리·고속 주행에 유리합니다.'),
  (v_s2, 'on_sale', '기아', '쏘렌토', 'SUV', 2021, 31500000, 52000, '회색', '디젤', '자동', 2151, 7, '경기', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션','어댑티브크루즈','헤드업디스플레이'], '2021년식 쏘렌토 디젤 7인승으로 주행 5만2천km의 무사고 차량입니다. 대형 SUV의 여유로운 공간과 디젤의 경제성을 모두 갖췄습니다. 가족 단위 캠핑·여행에 인기가 높은 모델입니다.'),
  (v_s2, 'on_sale', '현대', '팰리세이드', 'SUV', 2022, 39800000, 38000, '검정', '디젤', '자동', 2199, 7, '서울', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션','어댑티브크루즈','헤드업디스플레이'], '2022년식 팰리세이드 디젤 7인승으로 주행 3만8천km의 무사고 차량입니다. 대형 SUV 특유의 웅장한 외관과 고급스러운 실내로 만족도가 높습니다. 풀옵션 사양에 정숙성이 뛰어납니다.'),
  (v_s2, 'on_sale', 'KG모빌리티', '토레스', 'SUV', 2023, 27000000, 24000, '녹색', '가솔린', '자동', 1497, 5, '충북', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션'], '2023년식 토레스로 주행 2만4천km의 무사고 차량입니다. 각진 정통 SUV 디자인으로 개성이 뚜렷하고 실내공간이 넓습니다. 충북 지역 차량으로 관리 상태가 우수합니다.'),
  (v_s2, 'on_sale', 'KG모빌리티', '렉스턴', 'SUV', 2020, 25500000, 71000, '흰색', '디젤', '자동', 2157, 7, '경북', true, array['후방카메라','통풍시트','내비게이션','어댑티브크루즈'], '2020년식 렉스턴 디젤 7인승으로 주행 7만1천km의 무사고 대형 SUV입니다. 견고한 프레임 차체로 험로 주행과 견인에 강합니다. 경북 지역에서 잘 관리된 차량입니다.'),
  (v_s2, 'on_sale', 'KG모빌리티', '티볼리', 'SUV', 2019, 13800000, 64000, '빨강', '가솔린', '자동', 1597, 5, '전북', true, array['후방카메라','열선시트','스마트키'], '2019년식 티볼리로 주행 6만4천km의 무사고 소형 SUV입니다. 아담한 크기로 운전이 쉽고 유지비가 적게 듭니다. 사회초년생 첫차로 인기가 많은 모델입니다.'),
  (v_s2, 'on_sale', '르노코리아', 'QM6', 'SUV', 2021, 21500000, 45000, '은색', 'LPG', '자동', 1998, 5, '경남', true, array['후방카메라','통풍시트','내비게이션','스마트키'], '2021년식 QM6 LPG 모델로 주행 4만5천km의 무사고 차량입니다. SUV임에도 LPG라 연료비 부담이 적어 경제적입니다. 정숙한 주행감과 넓은 트렁크가 장점입니다.'),
  (v_s2, 'on_sale', '르노코리아', 'XM3', 'SUV', 2022, 20800000, 31000, '검정', '가솔린', '자동', 1332, 5, '경기', true, array['후방카메라','열선시트','내비게이션','크루즈컨트롤'], '2022년식 XM3로 주행 3만1천km의 무사고 차량입니다. 쿠페형 SUV 디자인으로 스타일리시한 외관이 돋보입니다. 경기 지역 차량으로 도심형 SUV를 원하는 분께 적합합니다.'),
  (v_s2, 'on_sale', '현대', '베뉴', 'SUV', 2020, 14500000, 58000, '흰색', '가솔린', '자동', 1591, 5, '대구', true, array['후방카메라','블루투스','스마트키'], '2020년식 베뉴로 주행 5만8천km의 무사고 엔트리 SUV입니다. 작고 경쾌한 차체로 도심 주행과 주차가 편리합니다. 합리적인 가격대로 첫차 SUV를 찾는 분께 추천합니다.'),
  (v_s2, 'on_sale', '기아', '카니발', 'RV', 2021, 33500000, 59000, '검정', '디젤', '자동', 2199, 9, '경기', true, array['후방카메라','통풍시트','파노라마선루프','내비게이션','어댑티브크루즈'], '2021년식 카니발 9인승 디젤로 주행 5만9천km의 무사고 차량입니다. 넓은 실내로 대가족·다인승 이동에 최적의 미니밴입니다. 경기 지역에서 패밀리카로 운행한 차량입니다.'),
